def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' not in line:
            continue
        k, v = line.split(':', 1)
        k = k.strip().lower(); v = v.strip()
        if k in ('affected_hosts', 'hosts'):
            out['affected_hosts'] = int(v) if v.lstrip('-').isdigit() else 0
        elif k in ('indicator', 'ioc', 'signature'):
            out['threat_present'] = bool(v) and v.lower() not in ('none', 'clean')
    return out
